module ALU_Unit(
  input         clock,
                reset,
                io_req_valid,
  input  [63:0] io_req_bits_uop_pc,
  input  [9:0]  io_req_bits_uop_alu_op,
  input  [1:0]  io_req_bits_uop_op1_sel,
  input  [2:0]  io_req_bits_uop_op2_sel,
  input  [63:0] io_req_bits_uop_imm,
  input         io_req_bits_uop_is_w,
  input  [3:0]  io_req_bits_uop_br_type,
  input  [5:0]  io_req_bits_uop_p_rd,
  input  [3:0]  io_req_bits_uop_rob_idx,
  input         io_req_bits_uop_exception,
  input  [63:0] io_req_bits_rs1_data,
                io_req_bits_rs2_data,
  output        io_cdb_valid,
  output [3:0]  io_cdb_bits_rob_idx,
  output [5:0]  io_cdb_bits_p_rd,
  output [63:0] io_cdb_bits_data,
  output        io_cdb_bits_exc,
                io_br_redirect,
  output [63:0] io_br_redirect_pc,
  output        io_br_resolved
);

  wire [63:0]  op1 =
    io_req_bits_uop_op1_sel == 2'h1
      ? 64'h0
      : io_req_bits_uop_op1_sel == 2'h2 ? io_req_bits_uop_pc : io_req_bits_rs1_data;
  wire [63:0]  op2 =
    io_req_bits_uop_op2_sel == 3'h5
      ? 64'h4
      : io_req_bits_uop_op2_sel == 3'h2 ? io_req_bits_uop_imm : io_req_bits_rs2_data;
  wire [5:0]   shamt = io_req_bits_uop_is_w ? {1'h0, op2[4:0]} : op2[5:0];
  wire [126:0] _alu_out_T_7 = {63'h0, op1} << shamt;
  wire [63:0]  _GEN = {58'h0, shamt};
  wire [63:0]  alu_out =
    io_req_bits_uop_alu_op == 10'h9
      ? {63'h0, op1 < op2}
      : io_req_bits_uop_alu_op == 10'h8
          ? {63'h0, $signed(op1) < $signed(op2)}
          : io_req_bits_uop_alu_op == 10'h7
              ? $signed($signed(op1) >>> _GEN)
              : io_req_bits_uop_alu_op == 10'h6
                  ? op1 >> _GEN
                  : io_req_bits_uop_alu_op == 10'h5
                      ? _alu_out_T_7[63:0]
                      : io_req_bits_uop_alu_op == 10'h4
                          ? op1 ^ op2
                          : io_req_bits_uop_alu_op == 10'h3
                              ? op1 | op2
                              : io_req_bits_uop_alu_op == 10'h2
                                  ? op1 & op2
                                  : io_req_bits_uop_alu_op == 10'h1
                                      ? op1 - op2
                                      : io_req_bits_uop_alu_op == 10'h0
                                          ? op1 + op2
                                          : 64'h0;
  wire [63:0]  alu_out_final =
    io_req_bits_uop_is_w ? {{32{alu_out[31]}}, alu_out[31:0]} : alu_out;
  wire         is_eq = io_req_bits_rs1_data == io_req_bits_rs2_data;
  wire         is_lt = $signed(io_req_bits_rs1_data) < $signed(io_req_bits_rs2_data);
  wire         is_ltu = io_req_bits_rs1_data < io_req_bits_rs2_data;
  wire         _io_cdb_bits_data_T_1 = io_req_bits_uop_br_type == 4'h8;
  wire         _io_br_resolved_T = io_req_bits_uop_br_type == 4'h1;
  wire         _io_br_resolved_T_1 = io_req_bits_uop_br_type == 4'h2;
  wire         _io_br_resolved_T_2 = io_req_bits_uop_br_type == 4'h3;
  wire         _io_br_resolved_T_3 = io_req_bits_uop_br_type == 4'h4;
  wire         _io_br_resolved_T_4 = io_req_bits_uop_br_type == 4'h5;
  wire         _io_br_resolved_T_5 = io_req_bits_uop_br_type == 4'h6;
  wire         is_mispredict =
    (_io_br_resolved_T | _io_br_resolved_T_1 | _io_br_resolved_T_2 | _io_br_resolved_T_3
     | _io_br_resolved_T_4 | _io_br_resolved_T_5)
    & (io_req_bits_uop_br_type == 4'h8 | io_req_bits_uop_br_type == 4'h7
       | (io_req_bits_uop_br_type == 4'h4
            ? ~is_ltu
            : io_req_bits_uop_br_type == 4'h6
                ? is_ltu
                : io_req_bits_uop_br_type == 4'h3
                    ? ~is_lt
                    : io_req_bits_uop_br_type == 4'h5
                        ? is_lt
                        : io_req_bits_uop_br_type == 4'h1
                            ? ~is_eq
                            : io_req_bits_uop_br_type == 4'h2 & is_eq));
  wire         _io_cdb_bits_data_T = io_req_bits_uop_br_type == 4'h7;
  wire         is_jump = _io_cdb_bits_data_T | _io_cdb_bits_data_T_1;
  `ifndef SYNTHESIS
    always @(posedge clock) begin
      if ((`PRINTF_COND_) & io_req_valid & ~reset)
        $fwrite(32'h80000002,
                "[ALU] PC: 0x%x | OP1: %d | OP2: %d | Result: %d | is_mispredict: %b\n",
                io_req_bits_uop_pc, op1, op2, alu_out_final, is_mispredict);
    end // always @(posedge)
  `endif // not def SYNTHESIS
  assign io_cdb_valid = io_req_valid;
  assign io_cdb_bits_rob_idx = io_req_bits_uop_rob_idx;
  assign io_cdb_bits_p_rd = io_req_bits_uop_p_rd;
  assign io_cdb_bits_data =
    _io_cdb_bits_data_T | _io_cdb_bits_data_T_1
      ? io_req_bits_uop_pc + 64'h4
      : alu_out_final;
  assign io_cdb_bits_exc = io_req_bits_uop_exception;
  assign io_br_redirect = io_req_valid & (is_mispredict | is_jump);
  assign io_br_redirect_pc =
    _io_cdb_bits_data_T_1 ? 64'h0 : io_req_bits_uop_pc + io_req_bits_uop_imm;
  assign io_br_resolved =
    io_req_valid
    & (_io_br_resolved_T | _io_br_resolved_T_1 | _io_br_resolved_T_2 | _io_br_resolved_T_3
       | _io_br_resolved_T_4 | _io_br_resolved_T_5 | is_jump);
endmodule

