module ram_4x130(
  input  [1:0]   R0_addr,
  input          R0_en,
                 R0_clk,
  output [129:0] R0_data,
  input  [1:0]   W0_addr,
  input          W0_en,
                 W0_clk,
  input  [129:0] W0_data
);

  reg [129:0] Memory[0:3];
  always @(posedge W0_clk) begin
    if (W0_en & 1'h1)
      Memory[W0_addr] <= W0_data;
  end // always @(posedge)
  assign R0_data = R0_en ? Memory[R0_addr] : 130'bx;
endmodule

module Queue4_StoreBufferEntry(
  input         clock,
                reset,
  output        io_enq_ready,
  input         io_enq_valid,
  input  [63:0] io_enq_bits_addr,
                io_enq_bits_data,
  input  [1:0]  io_enq_bits_size,
  input         io_deq_ready,
  output        io_deq_valid,
  output [63:0] io_deq_bits_addr,
                io_deq_bits_data,
  output [1:0]  io_deq_bits_size,
  output [2:0]  io_count
);

  wire [129:0] _ram_ext_R0_data;
  reg  [1:0]   enq_ptr_value;
  reg  [1:0]   deq_ptr_value;
  reg          maybe_full;
  wire         ptr_match = enq_ptr_value == deq_ptr_value;
  wire         empty = ptr_match & ~maybe_full;
  wire         full = ptr_match & maybe_full;
  wire         do_enq = ~full & io_enq_valid;
  always @(posedge clock) begin
    if (reset) begin
      enq_ptr_value <= 2'h0;
      deq_ptr_value <= 2'h0;
      maybe_full <= 1'h0;
    end
    else begin
      automatic logic do_deq = io_deq_ready & ~empty;
      if (do_enq)
        enq_ptr_value <= enq_ptr_value + 2'h1;
      if (do_deq)
        deq_ptr_value <= deq_ptr_value + 2'h1;
      if (~(do_enq == do_deq))
        maybe_full <= do_enq;
    end
  end // always @(posedge)
  ram_4x130 ram_ext (
    .R0_addr (deq_ptr_value),
    .R0_en   (1'h1),
    .R0_clk  (clock),
    .R0_data (_ram_ext_R0_data),
    .W0_addr (enq_ptr_value),
    .W0_en   (do_enq),
    .W0_clk  (clock),
    .W0_data ({io_enq_bits_size, io_enq_bits_data, io_enq_bits_addr})
  );
  assign io_enq_ready = ~full;
  assign io_deq_valid = ~empty;
  assign io_deq_bits_addr = _ram_ext_R0_data[63:0];
  assign io_deq_bits_data = _ram_ext_R0_data[127:64];
  assign io_deq_bits_size = _ram_ext_R0_data[129:128];
  assign io_count = {maybe_full & ptr_match, enq_ptr_value - deq_ptr_value};
endmodule

module LSU_Unit(
  input         clock,
                reset,
  output        io_req_ready,
  input         io_req_valid,
  input  [63:0] io_req_bits_uop_imm,
  input  [2:0]  io_req_bits_uop_mem_cmd,
  input  [1:0]  io_req_bits_uop_mem_size,
  input         io_req_bits_uop_mem_signed,
  input  [5:0]  io_req_bits_uop_p_rd,
  input  [3:0]  io_req_bits_uop_rob_idx,
  input         io_req_bits_uop_exception,
  input  [63:0] io_req_bits_rs1_data,
                io_req_bits_rs2_data,
  output        io_cdb_valid,
  output [3:0]  io_cdb_bits_rob_idx,
  output [5:0]  io_cdb_bits_p_rd,
  output [63:0] io_cdb_bits_data,
  output        io_cdb_bits_exc,
  input         io_dmem_req_ready,
  output        io_dmem_req_valid,
  output [63:0] io_dmem_req_bits_addr,
                io_dmem_req_bits_data,
  output [2:0]  io_dmem_req_bits_cmd,
  output [1:0]  io_dmem_req_bits_size,
  input         io_dmem_resp_valid,
  input  [63:0] io_dmem_resp_bits_data,
  input         io_commit_store
);

  wire             io_req_ready_0;
  wire             _store_buffer_io_enq_ready;
  wire             _store_buffer_io_deq_valid;
  wire [63:0]      _store_buffer_io_deq_bits_addr;
  wire [1:0]       _store_buffer_io_deq_bits_size;
  wire [2:0]       _store_buffer_io_count;
  wire [63:0]      _effective_addr_T = io_req_bits_rs1_data + io_req_bits_uop_imm;
  wire [3:0][63:0] _GEN =
    {{{2{io_req_bits_rs2_data[31:0]}}},
     {{2{{2{io_req_bits_rs2_data[15:0]}}}}},
     {{2{{2{{2{io_req_bits_rs2_data[7:0]}}}}}}},
     {io_req_bits_rs2_data}};
  wire             is_store = io_req_bits_uop_mem_cmd == 3'h2;
  wire             is_load = io_req_bits_uop_mem_cmd == 3'h1;
  wire             _store_buffer_io_enq_valid_T = io_req_ready_0 & io_req_valid;
  wire             _store_buffer_io_enq_valid_T_1 =
    _store_buffer_io_enq_valid_T & is_store;
  wire             _store_buffer_io_deq_ready_T = io_commit_store & io_dmem_req_ready;
  `ifndef SYNTHESIS
    always @(posedge clock) begin
      automatic logic _GEN_0 =
        _store_buffer_io_enq_ready & _store_buffer_io_enq_valid_T_1;
      automatic logic _GEN_1 = _store_buffer_io_deq_ready_T & _store_buffer_io_deq_valid;
      if ((`PRINTF_COND_) & (_GEN_0 | _GEN_1 | (|_store_buffer_io_count)) & ~reset)
        $fwrite(32'h80000002, "[SB-STATUS %d/4 | %d | %d\n", _store_buffer_io_count,
                ~_store_buffer_io_enq_ready, ~_store_buffer_io_deq_valid);
      if ((`PRINTF_COND_) & _GEN_0 & ~reset)
        $fwrite(32'h80000002, "  ---> [SB-PUSH] 0x%x,  %d\n", _effective_addr_T,
                _GEN[io_req_bits_uop_mem_size]);
      if ((`PRINTF_COND_) & _GEN_1 & ~reset)
        $fwrite(32'h80000002, "  <--- [SB-POP] 0x%x\n", _store_buffer_io_deq_bits_addr);
    end // always @(posedge)
  `endif // not def SYNTHESIS
  reg              state;
  reg  [1:0]       load_uop_reg_mem_size;
  reg              load_uop_reg_mem_signed;
  reg  [5:0]       load_uop_reg_p_rd;
  reg  [3:0]       load_uop_reg_rob_idx;
  reg              load_uop_reg_exception;
  reg  [63:0]      load_addr_reg;
  assign io_req_ready_0 =
    ~state
    & (is_store ? _store_buffer_io_enq_ready : is_load & ~_store_buffer_io_deq_valid);
  wire             _GEN_2 = state & io_dmem_resp_valid;
  wire             do_load_req =
    io_req_valid & is_load & ~_store_buffer_io_deq_valid & ~state;
  wire [63:0]      shifted_data =
    io_dmem_resp_bits_data >> {58'h0, load_addr_reg[2:0], 3'h0};
  wire [3:0][63:0] _GEN_3 =
    {{{load_uop_reg_mem_signed ? {32{shifted_data[31]}} : 32'h0, shifted_data[31:0]}},
     {{load_uop_reg_mem_signed ? {48{shifted_data[15]}} : 48'h0, shifted_data[15:0]}},
     {{load_uop_reg_mem_signed ? {56{shifted_data[7]}} : 56'h0, shifted_data[7:0]}},
     {io_dmem_resp_bits_data}};
  wire             _GEN_4 = _store_buffer_io_enq_valid_T & is_store;
  wire             _GEN_5 = _GEN_4 | ~_GEN_2;
  always @(posedge clock) begin
    automatic logic _GEN_6;
    _GEN_6 = _store_buffer_io_enq_valid_T & is_load;
    if (reset)
      state <= 1'h0;
    else
      state <= _GEN_6 | ~_GEN_2 & state;
    if (_GEN_6) begin
      load_uop_reg_mem_size <= io_req_bits_uop_mem_size;
      load_uop_reg_mem_signed <= io_req_bits_uop_mem_signed;
      load_uop_reg_p_rd <= io_req_bits_uop_p_rd;
      load_uop_reg_rob_idx <= io_req_bits_uop_rob_idx;
      load_uop_reg_exception <= io_req_bits_uop_exception;
      load_addr_reg <= _effective_addr_T;
    end
  end // always @(posedge)
  Queue4_StoreBufferEntry store_buffer (
    .clock            (clock),
    .reset            (reset),
    .io_enq_ready     (_store_buffer_io_enq_ready),
    .io_enq_valid     (_store_buffer_io_enq_valid_T_1),
    .io_enq_bits_addr (_effective_addr_T),
    .io_enq_bits_data (_GEN[io_req_bits_uop_mem_size]),
    .io_enq_bits_size (io_req_bits_uop_mem_size),
    .io_deq_ready     (_store_buffer_io_deq_ready_T),
    .io_deq_valid     (_store_buffer_io_deq_valid),
    .io_deq_bits_addr (_store_buffer_io_deq_bits_addr),
    .io_deq_bits_data (io_dmem_req_bits_data),
    .io_deq_bits_size (_store_buffer_io_deq_bits_size),
    .io_count         (_store_buffer_io_count)
  );
  assign io_req_ready = io_req_ready_0;
  assign io_cdb_valid = _GEN_4 | _GEN_2;
  assign io_cdb_bits_rob_idx =
    _GEN_4 ? io_req_bits_uop_rob_idx : _GEN_2 ? load_uop_reg_rob_idx : 4'h0;
  assign io_cdb_bits_p_rd = _GEN_5 ? 6'h0 : load_uop_reg_p_rd;
  assign io_cdb_bits_data = _GEN_5 ? 64'h0 : _GEN_3[load_uop_reg_mem_size];
  assign io_cdb_bits_exc =
    _GEN_4 ? io_req_bits_uop_exception : _GEN_2 & load_uop_reg_exception;
  assign io_dmem_req_valid = do_load_req | _store_buffer_io_deq_valid & io_commit_store;
  assign io_dmem_req_bits_addr =
    do_load_req ? _effective_addr_T : _store_buffer_io_deq_bits_addr;
  assign io_dmem_req_bits_cmd = {1'h0, do_load_req ? 2'h1 : 2'h2};
  assign io_dmem_req_bits_size =
    do_load_req ? io_req_bits_uop_mem_size : _store_buffer_io_deq_bits_size;
endmodule

